import re


def extract_error_type(traceback_str):
    lines = traceback_str.strip().splitlines()
    last_line = lines[-1].strip()
    if ':' in last_line:
        return last_line.split(':')[0].strip()
    return last_line.strip()


def extract_error_message(traceback_str):
    lines = traceback_str.strip().splitlines()
    last_line = lines[-1].strip()
    if ':' in last_line:
        return last_line.split(':', 1)[1].strip()
    return ''


def count_frames(traceback_str):
    return len(re.findall(r'File "', traceback_str))


def get_error_location(traceback_str):
    file_lines = re.findall(r'File "([^"]+)", line (\d+), in (\S+)', traceback_str)
    if not file_lines:
        return {'file': '', 'line': 0, 'function': ''}
    last = file_lines[-1]
    return {'file': last[0], 'line': int(last[1]), 'function': last[2]}
